Here's a modern MSTest test class covering async success, failure, timeout, and cancellation:

```csharp
[TestClass]
public class DataFetcherTests
{
    // MSTest natively supports async Task test methods — no need for .Result or .Wait()
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new MockHttpMessageHandler("hello", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_OnHttpError()
    {
        var handler = new MockHttpMessageHandler("", HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    // Use [Timeout] to fail tests that hang — value is in milliseconds
    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_CompletesWithinTimeout()
    {
        var handler = new MockHttpMessageHandler("fast", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("fast", result);
    }

    // Verify the method honors CancellationToken
    [TestMethod]
    public async Task FetchAsync_ThrowsOnCancellation()
    {
        var handler = new MockHttpMessageHandler("", HttpStatusCode.OK, delay: TimeSpan.FromSeconds(10));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Reusable fake handler — no external mocking library needed
    private sealed class MockHttpMessageHandler : HttpMessageHandler
    {
        private readonly string _content;
        private readonly HttpStatusCode _statusCode;
        private readonly TimeSpan _delay;

        public MockHttpMessageHandler(string content, HttpStatusCode statusCode,
            TimeSpan delay = default)
        {
            _content = content;
            _statusCode = statusCode;
            _delay = delay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay > TimeSpan.Zero)
                await Task.Delay(_delay, cancellationToken);

            return new HttpResponseMessage(_statusCode)
            {
                Content = new StringContent(_content)
            };
        }
    }
}
```

**Key patterns used:**

| Pattern | How |
|---|---|
| **Async tests** | `async Task` return type — MSTest awaits natively |
| **Timeout** | `[Timeout(ms)]` attribute fails the test if it hangs |
| **Cancellation** | Pre-cancelled `CancellationTokenSource` + assert `TaskCanceledException` |
| **No real HTTP** | Custom `HttpMessageHandler` subclass — no network, no mocking library |
| **Exception testing** | `Assert.ThrowsExceptionAsync<T>()` for async throws |

> **Avoid** `[Timeout]` on every test — reserve it for tests where hanging is a real risk (e.g., I/O, semaphores). MSTest's global test timeout in `.runsettings` is better for blanket protection.
